        </span>
        <span
          className="font-orbitron font-bold text-sm text-teal"
        >
          .ai
        </span>
      </a>

      {/* ナビリンク */}
      <div className="hidden md:flex items-center gap-8">
        {["機能", "使い方", "学習記録"].map((label) => (
          <a
            key={label}
            href={`#${label}`}
            className="text-sm tracking-wide transition-colors duration-200 text-muted-foreground"
          >
            {label}
          </a>
        ))}
      </div>

      {/* CTA */}
      <button className="juku-cta-btn-primary px-5 py-2 text-xs font-orbitron font-bold uppercase tracking-widest">
        <span>無料で始める</span>
